 1→import { useEffect, useRef } from 'react';
 2→import { supabase } from '../lib/supabase';
 3→import { queryClient } from '../lib/queryClient';
 4→import type { RealtimeChannel } from '@supabase/supabase-js';
 5→
 6→type Options = {
 7→  onNewNotification?: (payload: Record<string, unknown>) => void;
 8→};
 9→
10→export function useRealtimeNotifications(
11→  userId: string | undefined,
12→  options?: Options,
13→) {
14→  const callbackRef = useRef(options?.onNewNotification);
15→  callbackRef.current = options?.onNewNotification;
16→
17→  useEffect(() => {
18→    if (!userId || !supabase) return;
19→    const client = supabase;
20→
21→    const invalidate = () => {
22→      queryClient.invalidateQueries({ queryKey: ['notifications', userId] });
23→      queryClient.invalidateQueries({ queryKey: ['notification-count', userId] });
24→    };
25→
26→    const channel: RealtimeChannel = client
27→      .channel(`notifications:${userId}`)
28→      .on(
29→        'postgres_changes',
30→        {
31→          event: 'INSERT',
32→          schema: 'public',
33→          table: 'notifications',
34→          filter: `receiver_id=eq.${userId}`,
35→        },
36→        (payload) => {
37→          invalidate();
38→          callbackRef.current?.(payload.new as Record<string, unknown>);
39→        },
40→      )
41→      .on(
42→        'postgres_changes',
43→        {
44→          event: 'INSERT',
45→          schema: 'public',
46→          table: 'notification_opinions',
47→          filter: `receiver_id=eq.${userId}`,
48→        },
49→        (payload) => {
50→          invalidate();
51→          callbackRef.current?.(payload.new as Record<string, unknown>);
52→        },
53→      )
54→      .subscribe();
55→
56→    return () => {
57→      client.removeChannel(channel);
58→    };
59→  }, [userId]);
60→}
61→

  1→import React, {useState} from 'react';
  2→import {
  3→  Alert,
  4→  KeyboardAvoidingView,
  5→  Platform,
  6→  StyleSheet,
  7→  Text,
  8→  TextInput,
  9→  View,
 10→} from 'react-native';
 11→import {NativeStackScreenProps} from '@react-navigation/native-stack';
 12→import {SafeAreaView} from 'react-native-safe-area-context';
 13→import {PrimaryButton} from '../../components/PrimaryButton';
 14→import {useTheme} from '../../theme/ThemeProvider';
 15→import {fonts, typeScale} from '../../theme/typography';
 16→import {spacing, radii} from '../../theme/spacing';
 17→import type {AuthStackParamList} from '../../navigation/types';
 18→
 19→type Props = NativeStackScreenProps<AuthStackParamList, 'ForgotPassword'>;
 20→
 21→export function ForgotPasswordScreen({navigation}: Props) {
 22→  const {colors, isDark} = useTheme();
 23→  const [email, setEmail] = useState('');
 24→  const [loading, setLoading] = useState(false);
 25→  const [sent, setSent] = useState(false);
 26→  const [focusedField, setFocusedField] = useState<string | null>(null);
 27→
 28→  const onSubmit = async () => {
 29→    if (email.trim().length < 5) return;
 30→    try {
 31→      setLoading(true);
 32→      // Use Supabase directly for password reset
 33→      const {createClient} = await import('@supabase/supabase-js');
 34→      const {MOBILE_ENV} = await import('../../config/env');
 35→      if (MOBILE_ENV.SUPABASE_URL && MOBILE_ENV.SUPABASE_ANON_KEY) {
 36→        const supabase = createClient(
 37→          MOBILE_ENV.SUPABASE_URL,
 38→          MOBILE_ENV.SUPABASE_ANON_KEY,
 39→        );
 40→        await supabase.auth.resetPasswordForEmail(email.trim());
 41→      }
 42→      setSent(true);
 43→    } catch {
 44→      Alert.alert('Error', 'Failed to send reset email. Please try again.');
 45→    } finally {
 46→      setLoading(false);
 47→    }
 48→  };
 49→
 50→  const inputStyle = [
 51→    styles.input,
 52→    {
 53→      backgroundColor: isDark ? colors.bgElevated : colors.bgPrimary,
 54→      borderColor:
 55→        focusedField === 'email' ? colors.accentAmber : colors.borderCard,
 56→      color: colors.textPrimary,
 57→    },
 58→  ];
 59→
 60→  return (
 61→    <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
 62→      <KeyboardAvoidingView
 63→        style={styles.flex}
