 32→const formatRelativeDate = (value?: string): string => {
 33→  if (!value) return '';
 34→  const date = new Date(value);
 35→  if (Number.isNaN(date.getTime())) return value;
 36→  const diff = Date.now() - date.getTime();
 37→  const mins = Math.floor(diff / 60000);
 38→  if (mins < 1) return 'Just now';
 39→  if (mins < 60) return `${mins}m`;
 40→  const hours = Math.floor(mins / 60);
 41→  if (hours < 24) return `${hours}h`;
 42→  const days = Math.floor(hours / 24);
 43→  if (days < 7) return `${days}d`;
 44→  return date.toLocaleDateString(undefined, {month: 'short', day: 'numeric'});
 45→};
 46→
 47→const formatTitle = (item: NotificationItem): string => {
 48→  if (item.message) return item.message;
 49→  const name = item.users?.name || 'Someone';
 50→  switch (item.type) {
 51→    case 'like': return `${name} liked your post`;
 52→    case 'comment': return `${name} commented on your post`;
 53→    case 'repost': return `${name} reposted your post`;
 54→    case 'reply': return `${name} replied`;
 55→    case 'match': return `${name} matched with you`;
 56→    default: return 'Notification';
 57→  }
 58→};
 59→
 60→const formatContext = (item: NotificationItem): string => {
 61→  const title = item.journals?.title?.trim();
 62→  if (title) return title;
 63→  const opinion = item.opinions?.opinion?.trim();
 64→  if (opinion) return opinion.length > 100 ? `${opinion.slice(0, 97)}...` : opinion;
 65→  return '';
 66→};
 67→
 68→const getSource = (item: NotificationItem): 'journal' | 'opinion' => {
 69→  return item.source === 'opinion' || item.opinion_id ? 'opinion' : 'journal';
 70→};
