 72→function NotifIcon({type, color}: {type?: string; color: string}) {
 73→  switch (type) {
 74→    case 'like': return <HeartIcon size={14} color={color} filled />;
 75→    case 'comment': return <CommentIcon size={14} color={color} />;
 76→    case 'repost': return <RepostIcon size={14} color={color} />;
 77→    default: return <BellIcon size={14} color={color} />;
 78→  }
 79→}
