300→                type: 'text',
301→                text: payload.plainText,
302→                detail: 0,
303→                format: 0,
304→                mode: 'normal',
305→                style: '',
306→                version: 1,
307→              },
308→            ],
309→            direction: null,
310→            format: '',
311→            indent: 0,
312→            version: 1,
313→          },
314→        ],
315→        direction: null,
316→        format: '',
317→        indent: 0,
318→        type: 'root',
319→        version: 1,
