 1→import { QueryClient } from '@tanstack/react-query';
 2→import {
 3→  ApiError,
 4→  ApiNetworkError,
 5→  ApiTimeoutError,
 6→} from './api/apiClient';
 7→
 8→const MAX_QUERY_RETRIES = 2;
 9→
10→const isRetriableStatus = (status: number): boolean =>
11→  status === 408 || status === 429 || status >= 500;
12→
13→const shouldRetryQuery = (failureCount: number, error: unknown): boolean => {
14→  if (failureCount >= MAX_QUERY_RETRIES) {
15→    return false;
16→  }
17→
18→  if (error instanceof ApiTimeoutError || error instanceof ApiNetworkError) {
19→    return true;
20→  }
21→
22→  if (error instanceof ApiError) {
23→    return isRetriableStatus(error.status);
24→  }
25→
26→  return true;
27→};
28→
29→export const queryClient = new QueryClient({
30→  defaultOptions: {
31→    queries: {
32→      staleTime: 30 * 1000,
33→      gcTime: 5 * 60 * 1000,
34→      retry: shouldRetryQuery,
35→      retryDelay: (attempt) => Math.min(500 * 2 ** attempt, 4000),
36→      refetchOnReconnect: true,
37→      refetchOnMount: true,
38→      refetchOnWindowFocus: false,
39→    },
40→    mutations: {
41→      retry: 0,
42→    },
43→  },
44→});
